function LogicListener.onEntityItemSpawn(itemId, itemMeta, behavior, discard)
    if behavior == "break.block" then
        if CropsConfig:checkDropByItemid(itemId) then
            return true
        end
        return false
    end
    return true
end

function LogicListener.onItemSkillSpHandle(entityId, itemId, position)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return true
    end

    local skill = SkillConfig:getSkill(itemId)
    if skill ~= nil then
        GameSkill.new(skill, player, position)
    end
    return false
end

function LogicListener.onBlockFLowingChange(oldBlockId, newBlockId, vec3i, meta)

    local nowId = EngineWorld:getBlockId(vec3i)
    if CropsConfig:checkCropsByBlockId(nowId) then
        return false
    end

    local master = GameMatch:getMasterByPos(VectorUtil.toVector3(vec3i))

    if master then
        local masterManorInfo = GameMatch:getUserManorInfo(master.userId)
        if masterManorInfo then
            if newBlockId == BlockID.COBBLESTONE then
                if LogicListener.Timer[vec3i] ~= nil then
                    LuaTimer:cancel(LogicListener.Timer[vec3i])
                    LogicListener.Timer[vec3i] = nil
                end


                LogicListener.Timer[vec3i] = LuaTimer:schedule(function (vec3i)

                    if LogicListener.Timer[vec3i] ~= nil then
                        LuaTimer:cancel(LogicListener.Timer[vec3i])
                        LogicListener.Timer[vec3i] = nil
                    end


	    			local cur_blockId = EngineWorld:getBlockId(vec3i)
                    local master = GameMatch:getMasterByPos(VectorUtil.toVector3(vec3i))
                    if master and (cur_blockId == BlockID.WATER_MOVING or cur_blockId == BlockID.WATER_STILL or
            						cur_blockId == BlockID.LAVA_MOVING or cur_blockId == BlockID.LAVA_STILL) then
                        local masterManorInfo = GameMatch:getUserManorInfo(master.userId)
                        if masterManorInfo then
                            local integral = BlockSettingConfig:getIntegralByBlockId( newBlockId, meta)
                            EngineWorld:setBlock(vec3i, BlockID.COBBLESTONE)
                            master:addExp(integral)
                            master.taskController:packingProgressData(master, Define.TaskType.stone_machine, GameMatch.gameType, BlockID.COBBLESTONE, 1, 0)
                            masterManorInfo:recordBlock(vec3i, newBlockId, meta)
                        end
                    end
                end, 1000, 1, vec3i)
                return false
            end

            if oldBlockId == BlockID.ICE then
                if master and masterManorInfo then
                    masterManorInfo:recordWaterSource(vec3i)
                end
            end

            masterManorInfo:recordBlock(vec3i, newBlockId, meta)
            if (newBlockId == BlockID.WATER_MOVING or newBlockId == BlockID.WATER_STILL) and meta == 0 then
                if masterManorInfo:checkNewWaterSource(vec3i) then
                    master.taskController:packingProgressData(master, Define.TaskType.unlimite_Water, GameMatch.gameType, BlockID.WATER_MOVING, 1, 0)
                end
            end
            return true
        end
    else
        local manorInfo = GameMatch:getManorByPos(VectorUtil.toVector3(vec3i))
        if manorInfo then
            if manorInfo.release_status == Define.manorRelese.Not then
                return true
            end
        end
        return false
    end

    return false
end

function LogicListener.onCraftItemSuc(entityId, itemId, itemMeta, num)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return
    end
    player.taskController:packingProgressData(player, Define.TaskType.create, GameMatch.gameType, itemId, num, itemMeta)
    player.taskController:packingProgressData(player, Define.TaskType.collect, GameMatch.gameType, itemId, num, itemMeta)
end

