function LogicListener.onUseItemBucketInBlockChange(entityId, itemID, pos, oldBlockId, newBlockId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return
    end

    local targetManorInfo = GameMatch:getUserManorInfo(player.target_user_id)
    if targetManorInfo then
        -- do not have power
        if not targetManorInfo:checkPower(player.userId, pos, "onUseItemBucketInBlockChange") then
            return
        end
        targetManorInfo:recordBlock(pos, newBlockId, 0)
    end
end

