function LogicListener.onUseItemBucket(entityId, itemId, vec3i)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return true
    end

    if ItemID.BUCKET_WATER == itemId then
        local targetManorInfo = GameMatch:getUserManorInfo(player.userId)
        if targetManorInfo ~= nil then
            targetManorInfo:recordWaterSource(vec3i)
        end
    end

    return true
end

function LogicListener.onUseHoeTool(userId, blockId, vec3i)
    local player = PlayerManager:getPlayerByUserId(userId)
    if not player then
        return false
    end

    if BlockID.GRASS == blockId or BlockID.DIRT == blockId then

        local targetManorInfo = GameMatch:getUserManorInfo(player.target_user_id)
        if targetManorInfo then
            if targetManorInfo:checkPower(player.userId, vec3i, "onUseHoeTool") then
                return true
            end
        end
    end

    MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
    return false
end

function LogicListener.onFurnaceBurningChange(vec3i, blockId, meta)
    local master = GameMatch:getMasterByPos(VectorUtil.toVector3(vec3i))
    if master then
        local targetManorInfo = GameMatch:getUserManorInfo(master.userId)
        if targetManorInfo ~= nil then
            if targetManorInfo.release_status == Define.manorRelese.Not then
                targetManorInfo:recordBlock(vec3i, blockId, meta)
            end
        end
    end
end

function LogicListener.onUseSignPostItem(userId, itemID)
    -- 这里仅判断留言板是否有放置权限
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return false
    end

    if player.isNotInPartyCreateOrOver == false then
        return false
    end

    -- in the main hall
    if player.isGenisland then
        MsgSender.sendCenterTipsToTarget(rakssid, 1, Messages:msgBlockPlaceTip())
        return false
    end

    local master = PlayerManager:getPlayerByUserId(player.target_user_id)
    if master == nil then
        return false
    end

    -- subkey is not load
    if not player:checkChunkLoad() then
        return false
    end

    if not DbUtil.CanSavePlayerData(master, DbUtil.TAG_SIGN) then
        return false
    end

    local targetManorInfo = GameMatch:getUserManorInfo(player.target_user_id)

    if targetManorInfo == nil then
        return false
    end

    if targetManorInfo:isLoadingBlock() then
        return false
    end

    -- do not have power
    if not targetManorInfo:checkPower(player.userId) then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
        return false
    end

    HostApi.log("onUseSignPostItem userId : " .. tostring(userId).." itemID : " ..itemID)

    return true

end

function LogicListener.onUseCustomItem(userId, itemID, pos)
    local player = PlayerManager:getPlayerByUserId(userId)
    if player == nil then
        return false
    end

    if player.isNotInPartyCreateOrOver == false then
        return false
    end

    -- in the main hall
    if player.isGenisland then
        MsgSender.sendCenterTipsToTarget(rakssid, 1, Messages:msgBlockPlaceTip())
        return false
    end

    local master = PlayerManager:getPlayerByUserId(player.target_user_id)
    if master == nil then
        return false
    end

    -- subkey is not load
    if not player:checkChunkLoad() then
        return false
    end

    if not DbUtil.CanSavePlayerData(master, DbUtil.TAG_ACTOR) then
        return false
    end

    -- just master can place
    if not GameMatch:isMaster(player.userId) then
        MsgSender.sendCenterTipsToTarget(rakssid, 1, Messages:msgBlockPlaceTip())
        return false
    end

    local targetManorInfo = GameMatch:getUserManorInfo(player.target_user_id)

    if targetManorInfo == nil then
        return false
    end

    if targetManorInfo:isLoadingBlock() then
        return false
    end

    -- do not have power
    if not targetManorInfo:checkPower(player.userId, pos, "onUseCustomItem") then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
        return false
    end

    local isCan, actor = GameConfig:isCanPlaceItem(itemID)
    if isCan then
        if targetManorInfo:recordActor(pos, itemID, actor) then
            return true
        else
            MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgActorTextLimit(GameConfig.canPlaceActorLimit))
        end
    end
    HostApi.log("onUseCustomItem userId : " .. tostring(userId).." itemID : " ..itemID.. " pos: " .. pos.x .. " " .. pos.y .. " " .. pos.z)

    return false
end

