function LogicListener.OnClickBlockSign(entityId, vec3i)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return false
    end

    -- in the main hall
    if player.isGenisland then
        return false
    end

    if player.isNotInPartyCreateOrOver == false then
        return false
    end

    local masterManorInfo = GameMatch:getUserManorInfo(player.target_user_id)
    if masterManorInfo == nil then
        return false
    end

    -- do not have power
    if not masterManorInfo:checkPower(player.userId, vec3i, "OnClickBlockSign") then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
        return false
    end

    -- master is not exist
    local master = PlayerManager:getPlayerByUserId(player.target_user_id)
    if master == nil then
        HostApi.log("OnClickBlockSign master is not exist :  master " .. tostring(player.userId) .. " target_user_id: " .. tostring(player.target_user_id))
        return false
    end

    local oldText = masterManorInfo:checkSignPostIsNew(vec3i) or ""
    local data ={}
    data.hashVec3i = vec3i.x .. ":" .. vec3i.y .. ":" .. vec3i.z
    data.oldText = oldText
    GamePacketSender:sendSignPostData(player.rakssid, json.encode(data))
    return true
end

function LogicListener.onCustomCropsOwner(operatorEntityId, platformUserId)
    local player = PlayerManager:getPlayerByEntityId(operatorEntityId)
    if player == nil then
        return
    end

    local master = PlayerManager:getPlayerByUserId(player.target_user_id)
    if master == nil then
        return
    end

    local masterManorInfo = GameMatch:getUserManorInfo(player.target_user_id)
    if masterManorInfo == nil then
        return
    end

    -- do not have power
    if not masterManorInfo:checkPower(player.userId) then
        return
    end

    platformUserId.value = master.userId
end

function LogicListener.onCraftOpenSpHandle(vec3, entityId)
    local player = PlayerManager:getPlayerByEntityId(entityId)
    if player == nil then
        return false
    end

    -- in the main hall
    if player.isGenisland then
        return false
    end

    local master = PlayerManager:getPlayerByUserId(player.target_user_id)
    if master == nil then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
        return false
    end

    local masterManorInfo = GameMatch:getUserManorInfo(player.target_user_id)
    if masterManorInfo == nil then
        return false
    end

    if not masterManorInfo:checkPower(player.userId, pos, "onCraftOpenSpHandle") then
        MsgSender.sendCenterTipsToTarget(player.rakssid, 1, Messages:msgCannotOperatorVistor())
        return false
    end

    if not DbUtil.CanSavePlayerData(master, DbUtil.TAG_FURNACE) then
        return false
    end

    if masterManorInfo:isLoadingBlock() then
        return false
    end

    if not player:checkChunkLoad() then
        return false
    end

    HostApi.log("onCraftOpenSpHandle userId: " .. tostring(player.userId) .. " targetId: " .. tostring(player.target_user_id)
            .. " " .. vec3.x .. " " .. vec3.y .. " " .. vec3.z)

    return true
end

return LogicListener